      raised: Color(0xFFA855F7),
      disable: Color(0xFFA855F7),
      bolder: Color(0xFF7E22CE),
      inverse: Color(0xFFA855F7),
      strong: Color(0xFFA855F7),
      disabled: Color(0xFFA855F7),
    ),
  ),
);

// ── Radius ──────────────────────────────────────────────────────────────────

/// Default radius tokens.
const BTechRadiusTheme btechRadius = BTechRadiusTheme(
  interactive: 8.0,
  card: 14.0,
  badge: 9999.0,
  tooltip: 2.0,
);

// ── Font ────────────────────────────────────────────────────────────────────

/// Default font tokens.
const BTechFontTheme btechFont = BTechFontTheme(
  family: BTechFontFamily(sans: 'Inter'),
);

// ── Theme builder ───────────────────────────────────────────────────────────

/// Build a default BTech [ThemeData]. Use when no tenant package is needed.
///
/// ```dart
/// MaterialApp(
///   theme:     btechTheme(),
///   darkTheme: btechTheme(brightness: Brightness.dark),
///   themeMode: ThemeMode.system,
/// )
/// ```
ThemeData btechTheme({Brightness brightness = Brightness.light, ThemeData? base}) =>
    buildBtechTheme(btechColor, _btechColorDark, btechRadius, btechFont,
                    brightness: brightness, base: base);
